#include<bits/stdc++.h>
using namespace std;

int a[101][21],s[101];

int main()
{
	int n,m;
	double pj[21];
	scanf("%d%d",&n,&m);
	memset(s,0,sizeof(s));
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			scanf("%d",&a[i][j]);
		}
	}
	for(int i=1;i<=m;i++)
	{ 
    	for(int j=1;j<=n;j++) 
        {
        	pj[i]+=a[j][i];
        }
    	pj[i]/=n;
    	for(int j=1;j<=n;j++)
		{
        	if(a[j][i]>=pj[i]) 
           	{
           	   s[j]++;
           	}
    	}
	}

	for(int i=1;i<=n;i++)
	{
		printf("%d\n",s[i]);
	}
	return 0;
}
